// Logger.js
import { AsyncStorage } from 'react-native';

const Logger = {
  logNetworkRequest: (url, options) => {
    console.log('Network Request:', { url, options });
  },
  logNetworkResponse: (url, response) => {
    console.debug('Network Response:', { url, response });
  },
  logAsyncStorageOperation: (operation, key, value) => {
    console.log('AsyncStorage Operation:', { operation, key, value });
  },
  logUserAction: (action, details) => {
    console.log('User Action:', { action, details });
  },
  logStateChange: (prevState, newState) => {
    console.debug('State Change:', { prevState, newState });
  },
  logAuthToken: (token) => {
    console.debug('Auth Token:', token);
  },
  logUserData: (userData) => {
    console.debug('User Data:', userData);
  },
  logApiResponse: (api, response) => {
    console.debug('API Response:', { api, response });
  }
};

// NetworkInterceptor.js
export const networkInterceptor = (fetch) => {
  return async (url, options) => {
    Logger.logNetworkRequest(url, options);
    const response = await fetch(url, options);
    Logger.logNetworkResponse(url, response);
    return response;
  };
};

// AsyncStorageInterceptor.js
export const asyncStorageInterceptor = {
  setItem: async (key, value) => {
    Logger.logAsyncStorageOperation('setItem', key, value);
    return AsyncStorage.setItem(key, value);
  },
  getItem: async (key) => {
    const value = await AsyncStorage.getItem(key);
    Logger.logAsyncStorageOperation('getItem', key, value);
    return value;
  },
  removeItem: async (key) => {
    Logger.logAsyncStorageOperation('removeItem', key);
    return AsyncStorage.removeItem(key);
  }
};

